/**
 * POS Module Types
 *
 * Type definitions for future POS (Point of Sale) module implementation.
 * This file defines interfaces for POS integration, order sync,
 * and receipt management.
 *
 * @module modules/_stubs/pos/types
 *
 * @example
 * ```typescript
 * import type {
 *   IPosService,
 *   PosConnection,
 *   PosOrder,
 * } from '@/modules/_stubs/pos';
 * ```
 */

// -----------------------------------------------------------------------------
// Enums
// -----------------------------------------------------------------------------

/**
 * POS provider
 */
export enum PosProvider {
  /** Adisyo POS */
  ADISYO = 'ADISYO',
  /** Protel POS */
  PROTEL = 'PROTEL',
  /** Mikro POS */
  MIKRO = 'MIKRO',
  /** Generic REST API */
  GENERIC_REST = 'GENERIC_REST',
  /** Custom integration */
  CUSTOM = 'CUSTOM',
}

/**
 * POS connection status
 */
export enum PosConnectionStatus {
  /** Connected and operational */
  CONNECTED = 'CONNECTED',
  /** Disconnected */
  DISCONNECTED = 'DISCONNECTED',
  /** Connection error */
  ERROR = 'ERROR',
  /** Connecting */
  CONNECTING = 'CONNECTING',
  /** Syncing data */
  SYNCING = 'SYNCING',
}

/**
 * Sync direction
 */
export enum SyncDirection {
  /** From E-Menum to POS */
  TO_POS = 'TO_POS',
  /** From POS to E-Menum */
  FROM_POS = 'FROM_POS',
  /** Bidirectional */
  BIDIRECTIONAL = 'BIDIRECTIONAL',
}

/**
 * Sync entity type
 */
export enum SyncEntityType {
  /** Order sync */
  ORDER = 'ORDER',
  /** Menu/Product sync */
  MENU = 'MENU',
  /** Category sync */
  CATEGORY = 'CATEGORY',
  /** Inventory sync */
  INVENTORY = 'INVENTORY',
  /** Customer sync */
  CUSTOMER = 'CUSTOMER',
  /** Payment sync */
  PAYMENT = 'PAYMENT',
}

/**
 * Sync status
 */
export enum SyncStatus {
  /** Sync pending */
  PENDING = 'PENDING',
  /** Sync in progress */
  IN_PROGRESS = 'IN_PROGRESS',
  /** Sync completed */
  COMPLETED = 'COMPLETED',
  /** Sync failed */
  FAILED = 'FAILED',
  /** Sync skipped */
  SKIPPED = 'SKIPPED',
}

// -----------------------------------------------------------------------------
// Entity Types
// -----------------------------------------------------------------------------

/**
 * POS connection entity
 */
export interface PosConnection {
  /** Connection ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Branch ID */
  branchId: string;
  /** POS provider */
  provider: PosProvider;
  /** Connection name */
  name: string;
  /** Status */
  status: PosConnectionStatus;
  /** API endpoint URL */
  apiEndpoint: string | null;
  /** Credentials (encrypted) */
  credentials: Record<string, unknown>;
  /** Configuration */
  config: PosConfig;
  /** Last sync timestamp */
  lastSyncAt: Date | null;
  /** Last error */
  lastError: string | null;
  /** Created at */
  createdAt: Date;
  /** Updated at */
  updatedAt: Date;
}

/**
 * POS configuration
 */
export interface PosConfig {
  /** Sync direction */
  syncDirection: SyncDirection;
  /** Auto sync enabled */
  autoSyncEnabled: boolean;
  /** Auto sync interval (minutes) */
  autoSyncIntervalMinutes: number;
  /** Entities to sync */
  syncEntities: SyncEntityType[];
  /** Menu mapping enabled */
  menuMappingEnabled: boolean;
  /** Receipt printing enabled */
  receiptPrintingEnabled: boolean;
  /** Cash drawer enabled */
  cashDrawerEnabled: boolean;
  /** Offline mode enabled */
  offlineModeEnabled: boolean;
}

/**
 * POS sync record
 */
export interface PosSyncRecord {
  /** Record ID */
  id: string;
  /** Connection ID */
  connectionId: string;
  /** Organization ID */
  organizationId: string;
  /** Entity type */
  entityType: SyncEntityType;
  /** Direction */
  direction: SyncDirection;
  /** Status */
  status: SyncStatus;
  /** Items synced */
  itemsSynced: number;
  /** Items failed */
  itemsFailed: number;
  /** Error message */
  errorMessage: string | null;
  /** Started at */
  startedAt: Date;
  /** Completed at */
  completedAt: Date | null;
  /** Duration (ms) */
  durationMs: number | null;
}

/**
 * POS order (external representation)
 */
export interface PosOrder {
  /** POS order ID */
  posOrderId: string;
  /** E-Menum order ID */
  emenumOrderId: string | null;
  /** Order number */
  orderNumber: string;
  /** Table number */
  tableNumber: string | null;
  /** Order items */
  items: PosOrderItem[];
  /** Subtotal */
  subtotal: number;
  /** Tax */
  tax: number;
  /** Discount */
  discount: number;
  /** Total */
  total: number;
  /** Payment status */
  paymentStatus: string;
  /** Created at */
  createdAt: Date;
}

/**
 * POS order item
 */
export interface PosOrderItem {
  /** POS item ID */
  posItemId: string;
  /** E-Menum item ID */
  emenumItemId: string | null;
  /** Item name */
  name: string;
  /** Quantity */
  quantity: number;
  /** Unit price */
  unitPrice: number;
  /** Total price */
  totalPrice: number;
  /** Modifiers */
  modifiers: string[];
  /** Notes */
  notes: string | null;
}

/**
 * Menu mapping
 */
export interface MenuMapping {
  /** Mapping ID */
  id: string;
  /** Connection ID */
  connectionId: string;
  /** E-Menum item ID */
  emenumItemId: string;
  /** POS item ID */
  posItemId: string;
  /** POS item name */
  posItemName: string;
  /** Is active */
  isActive: boolean;
  /** Created at */
  createdAt: Date;
  /** Updated at */
  updatedAt: Date;
}

// -----------------------------------------------------------------------------
// Request Types
// -----------------------------------------------------------------------------

/**
 * Create POS connection request
 */
export interface CreatePosConnectionRequest {
  /** Branch ID */
  branchId: string;
  /** POS provider */
  provider: PosProvider;
  /** Connection name */
  name: string;
  /** API endpoint (if applicable) */
  apiEndpoint?: string;
  /** Credentials */
  credentials: Record<string, unknown>;
  /** Configuration */
  config?: Partial<PosConfig>;
}

/**
 * Update POS connection request
 */
export interface UpdatePosConnectionRequest {
  /** Connection name */
  name?: string;
  /** API endpoint */
  apiEndpoint?: string;
  /** Credentials */
  credentials?: Record<string, unknown>;
  /** Configuration */
  config?: Partial<PosConfig>;
}

/**
 * Sync request
 */
export interface SyncRequest {
  /** Connection ID */
  connectionId: string;
  /** Entity types to sync */
  entityTypes?: SyncEntityType[];
  /** Force full sync */
  fullSync?: boolean;
}

/**
 * Create menu mapping request
 */
export interface CreateMenuMappingRequest {
  /** Connection ID */
  connectionId: string;
  /** E-Menum item ID */
  emenumItemId: string;
  /** POS item ID */
  posItemId: string;
  /** POS item name */
  posItemName: string;
}

// -----------------------------------------------------------------------------
// Response Types
// -----------------------------------------------------------------------------

/**
 * Connection test result
 */
export interface PosConnectionTestResult {
  /** Test passed */
  success: boolean;
  /** Response time (ms) */
  responseTimeMs: number;
  /** POS version (if available) */
  posVersion: string | null;
  /** Error message */
  errorMessage?: string;
  /** Capabilities */
  capabilities?: string[];
}

/**
 * Sync result
 */
export interface PosSyncResult {
  /** Sync successful */
  success: boolean;
  /** Sync record ID */
  syncRecordId: string;
  /** Items synced */
  itemsSynced: number;
  /** Items failed */
  itemsFailed: number;
  /** Errors */
  errors: Array<{ itemId: string; error: string }>;
  /** Duration (ms) */
  durationMs: number;
}

/**
 * POS stats
 */
export interface PosStats {
  /** Total syncs */
  totalSyncs: number;
  /** Successful syncs */
  successfulSyncs: number;
  /** Failed syncs */
  failedSyncs: number;
  /** Items synced today */
  itemsSyncedToday: number;
  /** Last sync timestamp */
  lastSyncAt: Date | null;
  /** Average sync duration (ms) */
  avgSyncDurationMs: number;
}

// -----------------------------------------------------------------------------
// Service Interfaces
// -----------------------------------------------------------------------------

/**
 * POS service interface
 */
export interface IPosService {
  /**
   * Create POS connection
   */
  createConnection(
    organizationId: string,
    request: CreatePosConnectionRequest
  ): Promise<PosConnection>;

  /**
   * Get connection by ID
   */
  getConnection(
    organizationId: string,
    connectionId: string
  ): Promise<PosConnection>;

  /**
   * List connections
   */
  listConnections(
    organizationId: string,
    branchId?: string
  ): Promise<PosConnection[]>;

  /**
   * Update connection
   */
  updateConnection(
    organizationId: string,
    connectionId: string,
    request: UpdatePosConnectionRequest
  ): Promise<PosConnection>;

  /**
   * Delete connection
   */
  deleteConnection(
    organizationId: string,
    connectionId: string
  ): Promise<void>;

  /**
   * Test connection
   */
  testConnection(
    organizationId: string,
    connectionId: string
  ): Promise<PosConnectionTestResult>;

  /**
   * Get connection stats
   */
  getStats(
    organizationId: string,
    connectionId: string
  ): Promise<PosStats>;
}

/**
 * POS integration service interface
 */
export interface IPosIntegrationService {
  /**
   * Sync data
   */
  sync(
    organizationId: string,
    request: SyncRequest
  ): Promise<PosSyncResult>;

  /**
   * Get sync history
   */
  getSyncHistory(
    organizationId: string,
    connectionId: string,
    limit?: number
  ): Promise<PosSyncRecord[]>;

  /**
   * Send order to POS
   */
  sendOrderToPOS(
    organizationId: string,
    connectionId: string,
    orderId: string
  ): Promise<{ success: boolean; posOrderId?: string; error?: string }>;

  /**
   * Get order from POS
   */
  getOrderFromPOS(
    organizationId: string,
    connectionId: string,
    posOrderId: string
  ): Promise<PosOrder>;

  /**
   * Create menu mapping
   */
  createMenuMapping(
    organizationId: string,
    request: CreateMenuMappingRequest
  ): Promise<MenuMapping>;

  /**
   * List menu mappings
   */
  listMenuMappings(
    organizationId: string,
    connectionId: string
  ): Promise<MenuMapping[]>;

  /**
   * Delete menu mapping
   */
  deleteMenuMapping(
    organizationId: string,
    mappingId: string
  ): Promise<void>;

  /**
   * Auto-map menu items
   */
  autoMapMenuItems(
    organizationId: string,
    connectionId: string
  ): Promise<{ mapped: number; unmapped: number }>;
}

// -----------------------------------------------------------------------------
// Event Payload Types
// -----------------------------------------------------------------------------

/**
 * POS connected event payload
 */
export interface PosConnectedEventPayload {
  organizationId: string;
  branchId: string;
  connectionId: string;
  provider: PosProvider;
  timestamp: string;
}

/**
 * POS disconnected event payload
 */
export interface PosDisconnectedEventPayload {
  organizationId: string;
  connectionId: string;
  reason: string;
  timestamp: string;
}

/**
 * POS order synced event payload
 */
export interface PosOrderSyncedEventPayload {
  organizationId: string;
  connectionId: string;
  emenumOrderId: string;
  posOrderId: string;
  direction: SyncDirection;
  timestamp: string;
}

/**
 * POS sync failed event payload
 */
export interface PosSyncFailedEventPayload {
  organizationId: string;
  connectionId: string;
  entityType: SyncEntityType;
  errorMessage: string;
  itemsFailed: number;
  timestamp: string;
}
